import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva, type VariantProps } from "class-variance-authority"
import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground shadow hover:bg-primary/90",
        destructive: "bg-destructive text-destructive-foreground shadow-sm hover:bg-destructive/90",
        outline: "border border-input bg-background shadow-sm hover:bg-accent hover:text-accent-foreground",
        secondary: "bg-secondary text-secondary-foreground shadow-sm hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-9 px-4 py-2",
        sm: "h-8 rounded-md px-3 text-xs",
        lg: "h-10 rounded-md px-8",
        icon: "h-9 w-9",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
)

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button"
    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        {...props}
      />
    )
  },
)
Button.displayName = "Button"

export { Button, buttonVariants }

import * as React from "react"
import { cn } from "@/lib/utils"

const Input = React.forwardRef<HTMLInputElement, React.InputHTMLAttributes<HTMLInputElement>>(
  ({ className, type, ...props }, ref) => {
    return (
      <input
        type={type}
        className={cn(
          "flex h-9 w-full rounded-md border border-input bg-transparent px-3 py-1 text-sm shadow-sm transition-colors file:border-0 file:bg-transparent file:text-sm file:font-medium file:text-foreground placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50",
          className,
        )}
        ref={ref}
        {...props}
      />
    )
  },
)
Input.displayName = "Input"

export { Input }

import * as React from "react"
import * as SeparatorPrimitive from "@radix-ui/react-separator"
import { cn } from "@/lib/utils"

const Separator = React.forwardRef<
  React.ComponentRef<typeof SeparatorPrimitive.Root>,
  React.ComponentPropsWithoutRef<typeof SeparatorPrimitive.Root>
>(({ className, orientation = "horizontal", decorative = true, ...props }, ref) => (
  <SeparatorPrimitive.Root
    ref={ref}
    decorative={decorative}
    orientation={orientation}
    className={cn(
      "shrink-0 bg-border",
      orientation === "horizontal" ? "h-[1px] w-full" : "h-full w-[1px]",
      className,
    )}
    {...props}
  />
))
Separator.displayName = SeparatorPrimitive.Root.displayName

export { Separator }

import { LogOut } from "lucide-react"
import { useTranslation } from "react-i18next"
import { logout } from "@/lib/auth"
import { Button } from "@/components/ui/button"
import type { User } from "@/types"

interface HeaderProps {
  user: User | undefined
}

export function Header({ user }: HeaderProps) {
  const { t } = useTranslation()

  return (
    <header className="sticky top-0 z-10 flex h-14 items-center justify-between border-b bg-white px-6">
      <span className="text-lg font-semibold">考试系统</span>

      {user && (
        <div className="flex items-center gap-3">
          <span className="text-sm text-muted-foreground">{user.displayName}</span>
          <Button variant="ghost" size="icon" onClick={logout} title={t("auth.logout")}>
            <LogOut className="h-4 w-4" />
          </Button>
        </div>
      )}
    </header>
  )
}

import { ClipboardList, History, Settings } from "lucide-react"
import { useTranslation } from "react-i18next"
import { Link, useRouterState } from "@tanstack/react-router"
import { cn } from "@/lib/utils"
import { Separator } from "@/components/ui/separator"

interface SideNavProps {
  isAdmin: boolean
}

interface NavItem {
  icon: React.ComponentType<{ className?: string }>
  labelKey: string
  to: string
}

const userNavItems: NavItem[] = [
  { icon: ClipboardList, labelKey: "nav.myExams", to: "/exams" },
  { icon: History, labelKey: "nav.records", to: "/records" },
]

const adminNavItems: NavItem[] = [
  { icon: Settings, labelKey: "nav.examManagement", to: "/admin/exams" },
]

export function SideNav({ isAdmin }: SideNavProps) {
  const { t } = useTranslation()
  const routerState = useRouterState()
  const currentPath = routerState.location.pathname

  return (
    <aside className="flex h-full w-56 shrink-0 flex-col border-r bg-white">
      <nav className="flex flex-1 flex-col gap-1 p-3">
        {userNavItems.map((item) => (
          <NavLink key={item.to} item={item} currentPath={currentPath} label={t(item.labelKey)} />
        ))}

        {isAdmin && (
          <>
            <Separator className="my-2" />
            {adminNavItems.map((item) => (
              <NavLink key={item.to} item={item} currentPath={currentPath} label={t(item.labelKey)} />
            ))}
          </>
        )}
      </nav>
    </aside>
  )
}

function NavLink({ item, currentPath, label }: { item: NavItem; currentPath: string; label: string }) {
  const isActive = currentPath.startsWith(item.to)
  const Icon = item.icon

  return (
    <Link
      to={item.to}
      className={cn(
        "flex items-center gap-3 rounded-md px-3 py-2 text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground",
        isActive && "bg-accent text-accent-foreground",
      )}
    >
      <Icon className="h-4 w-4" />
      {label}
    </Link>
  )
}

import { Outlet, createRootRoute } from "@tanstack/react-router"
import { Toaster } from "sonner"
import { lazy, Suspense } from "react"

const TanStackRouterDevtools =
  import.meta.env.PROD
    ? () => null
    : lazy(() =>
        import("@tanstack/react-router-devtools").then((res) => ({
          default: res.TanStackRouterDevtools,
        })),
      )

export const Route = createRootRoute({
  component: RootComponent,
})

function RootComponent() {
  return (
    <>
      <Outlet />
      <Toaster richColors position="top-right" />
      <Suspense>
        <TanStackRouterDevtools />
      </Suspense>
    </>
  )
}

import { createFileRoute, Navigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { getToken } from "@/lib/auth"
import { Button } from "@/components/ui/button"

export const Route = createFileRoute("/login")({
  component: LoginPage,
})

function LoginPage() {
  const { t } = useTranslation()

  // 已登录则跳转到考试列表
  if (getToken()) {
    return <Navigate to="/exams" />
  }

  const handleOAuthLogin = () => {
    window.location.href = "/api/auth/oauth2/login"
  }

  return (
    <div className="flex min-h-screen items-center justify-center bg-gray-50">
      <div className="w-full max-w-sm rounded-lg border bg-white p-8 shadow-sm">
        <div className="mb-6 text-center">
          <h1 className="text-2xl font-bold">考试系统</h1>
          <p className="mt-2 text-sm text-muted-foreground">
            请使用 OA 账号登录以继续
          </p>
        </div>

        <Button className="w-full" size="lg" onClick={handleOAuthLogin}>
          {t("auth.loginWithOA")}
        </Button>
      </div>
    </div>
  )
}

import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useEffect } from "react"
import { setToken } from "@/lib/auth"

export const Route = createFileRoute("/oauth/callback")({
  component: OAuthCallbackPage,
})

function OAuthCallbackPage() {
  const navigate = useNavigate()

  useEffect(() => {
    const params = new URLSearchParams(window.location.search)
    const token = params.get("token")

    if (token) {
      setToken(token)
      navigate({ to: "/exams" })
    } else {
      // 没有 token 参数，回到登录页
      navigate({ to: "/login" })
    }
  }, [navigate])

  return (
    <div className="flex min-h-screen items-center justify-center">
      <div className="flex items-center gap-2 text-muted-foreground">
        <div className="h-5 w-5 animate-spin rounded-full border-2 border-current border-t-transparent" />
        <span>正在处理登录...</span>
      </div>
    </div>
  )
}

import { Outlet, createFileRoute, redirect } from "@tanstack/react-router"
import { getToken } from "@/lib/auth"
import { useAuth } from "@/hooks/use-auth"
import { Header } from "@/components/layout/header"
import { SideNav } from "@/components/layout/side-nav"

export const Route = createFileRoute("/_layout")({
  beforeLoad: () => {
    if (!getToken()) {
      throw redirect({ to: "/login" })
    }
  },
  component: LayoutComponent,
})

function LayoutComponent() {
  const { user, isAdmin, isLoading } = useAuth()

  if (isLoading) {
    return (
      <div className="flex h-screen items-center justify-center">
        <div className="h-8 w-8 animate-spin rounded-full border-4 border-primary border-t-transparent" />
      </div>
    )
  }

  return (
    <div className="flex h-screen">
      <SideNav isAdmin={isAdmin} />
      <div className="flex flex-1 flex-col">
        <Header user={user} />
        <main className="flex-1 overflow-auto p-6">
          <Outlet />
        </main>
      </div>
    </div>
  )
}

import { Navigate, createFileRoute } from "@tanstack/react-router"

export const Route = createFileRoute("/_layout/")({
  component: LayoutIndex,
})

function LayoutIndex() {
  return <Navigate to="/exams" />
}
